import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

const projectRoot = process.cwd();
const repoRoot = path.resolve(projectRoot, "..");
const changelogPath = path.join(repoRoot, "CHANGELOG.md");
const generatedFilePath = path.join(projectRoot, "src", "lib", "generated-changelog.ts");

async function main() {
  const changelogContent = await readFile(changelogPath, "utf8");

  const generatedSource = [
    "// This file is generated by web/scripts/sync-site-documents.mjs.",
    "// Do not edit it manually.",
    `export const GENERATED_CHANGELOG_CONTENT = ${JSON.stringify(changelogContent)};`,
    "",
  ].join("\n");

  await mkdir(path.dirname(generatedFilePath), { recursive: true });
  await writeFile(generatedFilePath, generatedSource, "utf8");
}

main().catch((error) => {
  console.error("Failed to sync site documents.", error);
  process.exitCode = 1;
});